import { useState } from 'react';
import { useAuth0 } from "@auth0/auth0-react";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import type { Project } from './types';

const initialProjects: Project[] = [
    { id: '1', name: 'Alpha Migration', description: 'Migrate legacy data to the new cloud infrastructure. Ensure zero downtime.', status: 'active' },
    { id: '2', name: 'Beta Launch', description: 'Prepare marketing and deployment for the Beta release. Coordinate with design team.', status: 'on_hold' },
    { id: '3', name: 'Gamma Security Audit', description: 'Complete end-to-end security audit and penetration testing for Q3.', status: 'completed' },
];

function Projects() {
    const { isAuthenticated, user } = useAuth0();
    const [projects, setProjects] = useState<Project[]>(initialProjects);

    const getStatusVariant = (status: Project['status']) => {
        switch (status) {
            case 'active': return 'default';
            case 'completed': return 'secondary';
            case 'on_hold': return 'destructive';
            default: return 'outline';
        }
    };

    return (
        <div className="px-6 py-8 md:px-12 md:py-10 max-w-[1600px] mx-auto min-h-screen">
            <div className="mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold bg-gradient-to-r from-purple-400 to-indigo-500 bg-clip-text text-transparent">
                        Project Management
                    </h1>
                    <p className="text-gray-400 mt-2">Manage overarching projects and monitor their current statuses.</p>
                </div>
                <Button className="bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-500/20 px-6">
                    + New Project
                </Button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {projects.map((project) => (
                    <Card key={project.id} className="bg-[#1f2128] border-[#2b2d36] text-white hover:border-indigo-500/50 transition-colors duration-200">
                        <CardHeader className="pb-3">
                            <div className="flex justify-between items-start">
                                <CardTitle className="text-xl font-semibold tracking-tight">{project.name}</CardTitle>
                            </div>
                            <CardDescription className="text-gray-400 mt-1.5 leading-relaxed">{project.description}</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <div className="flex items-center gap-2 text-sm text-gray-500">
                                <span className="font-medium text-gray-300">Project ID:</span> <span className="text-gray-400">{project.id}</span>
                            </div>
                        </CardContent>
                        <CardFooter className="pt-4 border-t border-[#2b2d36] flex justify-between items-center mt-2">
                            <Badge variant={getStatusVariant(project.status)} className="capitalize px-3 py-1 bg-opacity-20 border-transparent">
                                {project.status.replace('_', ' ')}
                            </Badge>
                            <Button variant="ghost" size="sm" className="text-indigo-400 hover:text-indigo-300 hover:bg-indigo-500/10">
                                View Details &rarr;
                            </Button>
                        </CardFooter>
                    </Card>
                ))}
            </div>
        </div>
    );
}

export default Projects;

